// ─── STORAGE UNIVERSEL (window.storage si dispo, sinon mémoire locale) ───────
// Garantit que l'espace patient fonctionne même hors de l'environnement
// d'artifact Claude.ai (CodeSandbox, projet React local, etc.)
const memoryStore = new Map();
const hasRealStorage = typeof window !== "undefined" && window.storage && typeof window.storage.get === "function";

const storage = {
  async get(key, shared = false) {
    if (hasRealStorage) {
      try { return await window.storage.get(key, shared); }
      catch { /* clé absente ou erreur réseau : on tombe sur le fallback mémoire */ }
    }
    const k = (shared ? "shared:" : "local:") + key;
    if (!memoryStore.has(k)) throw new Error("not found");
    return { key, value: memoryStore.get(k), shared };
  },
  async set(key, value, shared = false) {
    if (hasRealStorage) {
      try {
        const result = await window.storage.set(key, value, shared);
        if (result) return result;
      } catch { /* on tombe sur le fallback mémoire */ }
    }
    const k = (shared ? "shared:" : "local:") + key;
    memoryStore.set(k, value);
    return { key, value, shared };
  },
  async delete(key, shared = false) {
    if (hasRealStorage) {
      try {
        const result = await window.storage.delete(key, shared);
        if (result) return result;
      } catch { /* on tombe sur le fallback mémoire */ }
    }
    const k = (shared ? "shared:" : "local:") + key;
    const existed = memoryStore.delete(k);
    return { key, deleted: existed, shared };
  }
};

