// ─── MODAL (plein écran sur mobile, centré sur desktop) ──────────────────────
function SpecModal({ sp, lang, t, onClose, onBook }) {
  const s = getSpec(sp, lang);
  const steps = getJourneySteps(sp.type, t);
  useEffect(() => {
    const onKey = e => e.key === "Escape" && onClose();
    document.addEventListener("keydown", onKey);
    document.body.style.overflow = "hidden";
    return () => { document.removeEventListener("keydown", onKey); document.body.style.overflow = ""; };
  }, [onClose]);
  return (
    <div role="dialog" aria-modal="true" aria-label={s.name} className="fixed inset-0 z-50 overflow-y-auto" style={{ background:"rgba(5,10,20,0.92)", backdropFilter:"blur(10px)" }} onClick={e => e.target===e.currentTarget && onClose()}>
      <div className="min-h-screen flex items-start sm:items-center justify-center p-0 sm:p-4">
        <div className="bg-white w-full sm:max-w-2xl sm:rounded-3xl overflow-hidden shadow-2xl min-h-screen sm:min-h-0 sm:max-h-[92vh] sm:overflow-y-auto">
          <div className="relative h-48 sm:h-56 overflow-hidden">
            <img src={sp.photo} alt={s.name} width="640" height="280" loading="eager" decoding="async" className="w-full h-full object-cover"/>
            <div className="absolute inset-0" style={{ background:"linear-gradient(to top, rgba(10,22,40,0.95) 0%, rgba(10,22,40,0.3) 60%, transparent)" }}/>
            <button onClick={onClose} aria-label="Fermer" className="absolute top-4 right-4 w-9 h-9 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center text-white hover:bg-white/40 transition-colors">
              <Ico.X/>
            </button>
            <div className="absolute bottom-5 left-5 right-5">
              <span className="text-xs font-semibold tracking-widest uppercase px-3 py-1 rounded-full mb-2 inline-block" style={{ background:"rgba(212,175,55,0.25)", color:GOLD, border:"1px solid rgba(212,175,55,0.4)" }}>{s.badge}</span>
              <h2 className="text-xl sm:text-2xl font-bold text-white" style={{ fontFamily:"'Cormorant Garamond',Georgia,serif" }}>{s.name}</h2>
              <p className="flex items-center gap-1.5 mt-1 text-sm" style={{ color:"rgba(212,175,55,0.8)" }}>
                <Ico.Pin/><span>{s.dest}</span>
              </p>
            </div>
          </div>

          <div className="p-5 sm:p-7 space-y-6">
            <p className="inline-block px-4 py-2 rounded-full text-xs sm:text-sm font-bold" style={{ background:`${sp.color}15`, color:sp.color, border:`1px solid ${sp.color}30` }}>
              {t.days_stay} : {sp.days}
            </p>

            <p className="text-gray-700 leading-relaxed text-sm sm:text-base">{s.summary}</p>

            <div>
              <h3 className="text-xs sm:text-sm font-bold tracking-wide uppercase mb-3" style={{ color:NAVY }}>Protocole de soins</h3>
              <ul className="grid grid-cols-1 gap-2">
                {s.bullets.map((b,i) => (
                  <li key={i} className="flex items-center gap-3">
                    <span className="w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0" style={{ background:sp.color }}><Ico.Check/></span>
                    <span className="text-sm text-gray-700">{b}</span>
                  </li>
                ))}
              </ul>
            </div>

            <div>
              <h3 className="text-xs sm:text-sm font-bold tracking-wide uppercase mb-4" style={{ color:NAVY }}>Votre parcours patient</h3>
              <ol className="space-y-3">
                {steps.map(([icon,title,desc],i) => (
                  <li key={i} className="flex gap-3 sm:gap-4">
                    <div className="flex flex-col items-center flex-shrink-0">
                      <span className="w-8 h-8 sm:w-9 sm:h-9 rounded-full flex items-center justify-center text-base sm:text-lg border" style={{ background:`${sp.color}10`, borderColor:`${sp.color}30` }} aria-hidden="true">{icon}</span>
                      {i < steps.length-1 && <span className="w-px flex-1 my-1" style={{ background:`${sp.color}20` }}/>}
                    </div>
                    <div className="pb-3">
                      <p className="text-sm font-bold" style={{ color:NAVY }}>{title}</p>
                      <p className="text-xs text-gray-500 leading-relaxed mt-0.5">{desc}</p>
                    </div>
                  </li>
                ))}
              </ol>
            </div>

            <button onClick={() => { onClose(); onBook(sp); }} className="w-full py-4 rounded-2xl text-[#0A1628] font-bold text-sm sm:text-base transition-transform active:scale-[0.98] sm:hover:scale-[1.01]" style={{ background:G }}>
              {t.cta_modal}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

