// ─── MAIN APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [lang, setLang] = useState("fr");
  const [menu, setMenu] = useState(false);
  const [section, setSection] = useState("home");
  const [modal, setModal] = useState(null);
  const [destModal, setDestModal] = useState(null);
  const [bookSp, setBookSp] = useState(null);
  const [cart, setCart] = useState([]);
  const [pendingAppointment, setPendingAppointment] = useState(null);
  const t = T[lang] || T.fr;
  const isRTL = lang === "ar";

  const go = (s) => { setSection(s); setMenu(false); window.scrollTo(0,0); };

  useEffect(() => {
    document.title = `${t.hero_title.replace("\n"," ")} — ${t.hero_sub}`;
  }, [lang]);

  const handleAppointmentConfirmed = (appointment, patientEmail) => {
    setPendingAppointment({ ...appointment, _targetEmail: patientEmail });
  };

  return (
    <div dir={isRTL?"rtl":"ltr"} style={{ fontFamily:"'DM Sans',system-ui,-apple-system,sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;0,700;1,400;1,600&family=DM+Sans:wght@300;400;500;600&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        html{scroll-behavior:smooth}
        body{overflow-x:hidden}
        img{max-width:100%;height:auto}
        button{touch-action:manipulation}
        .line-clamp-2{display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}
        @keyframes pulse{0%,100%{opacity:0.1}50%{opacity:0.4}}
        @keyframes bounce{0%,100%{transform:translateY(0)}50%{transform:translateY(-4px)}}
        @keyframes spin{to{transform:rotate(360deg)}}
        .animate-spin{animation:spin 0.8s linear infinite}
        @media (prefers-reduced-motion: reduce){*{animation-duration:0.01ms !important;transition-duration:0.01ms !important}}
        ::-webkit-scrollbar{width:5px}
        ::-webkit-scrollbar-track{background:#F8F6F0}
        ::-webkit-scrollbar-thumb{background:#D4AF37;border-radius:10px}
      `}</style>

      {/* NAVBAR — sticky, compact mobile, touch targets ≥ 44px */}
      <header className="sticky top-0 z-40" style={{ background:"rgba(6,14,26,0.96)", backdropFilter:"blur(20px)", borderBottom:"1px solid rgba(212,175,55,0.1)" }}>
        <nav aria-label="Navigation principale" className="max-w-7xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between">
          <button onClick={() => go("home")} className="flex items-center gap-2 sm:gap-3 min-w-0" aria-label="Retour à l'accueil">
            <img src={LOGO} alt="International Healthpoint Clinic" width="40" height="40" loading="eager" className="w-9 h-9 sm:w-10 sm:h-10 rounded-lg object-cover flex-shrink-0"/>
            <span className="font-bold text-white text-xs sm:text-sm hidden sm:block truncate" style={{ fontFamily:"'Cormorant Garamond',Georgia,serif", letterSpacing:"0.01em" }}>International Healthpoint Clinic</span>
          </button>

          <div className="hidden lg:flex items-center gap-7">
            {[["home",t.nav[0]],["specialties",t.nav[1]],["destinations",t.nav[2]],["patient",t.nav[3]]].map(([s,l]) => (
              <button key={s} onClick={() => go(s)} className="text-sm font-medium transition-colors" style={{ color:section===s ? GOLD : "rgba(255,255,255,0.6)" }}>{l}</button>
            ))}
          </div>

          <div className="flex items-center gap-2 sm:gap-3">
            <button onClick={() => go("shop")} aria-label="Boutique" className="relative w-9 h-9 sm:w-10 sm:h-10 rounded-full flex items-center justify-center text-white hover:bg-white/10 transition-colors flex-shrink-0">
              <span className="text-base sm:text-lg" aria-hidden="true">🛍️</span>
              {cart.length>0 && <span className="absolute -top-1 -right-1 w-4 h-4 rounded-full text-[9px] font-bold flex items-center justify-center" style={{ background:"#DC2626", color:"white" }}>{cart.reduce((s,i)=>s+i.qty,0)}</span>}
            </button>
            <select value={lang} onChange={e => setLang(e.target.value)} aria-label="Choisir la langue" className="text-[11px] sm:text-xs font-semibold px-2.5 sm:px-3 py-2 rounded-full outline-none cursor-pointer" style={{ background:"rgba(212,175,55,0.12)", color:GOLD, border:"1px solid rgba(212,175,55,0.25)" }}>
              <option value="fr">FR</option>
              <option value="en">EN</option>
              <option value="ar">AR</option>
              <option value="es">ES</option>
              <option value="de">DE</option>
            </select>
            <button onClick={() => go("booking")} className="hidden md:flex items-center gap-2 px-4 sm:px-5 py-2.5 rounded-full text-xs sm:text-sm font-bold transition-transform hover:scale-105" style={{ background:G, color:NAVY }}>
              <Ico.Cal/> {t.bookShort}
            </button>
            <button onClick={() => setMenu(!menu)} aria-label="Ouvrir le menu" aria-expanded={menu} className="lg:hidden w-10 h-10 flex items-center justify-center rounded-full text-white hover:bg-white/10 transition-colors flex-shrink-0">
              {menu ? <Ico.X/> : <Ico.Menu/>}
            </button>
          </div>
        </nav>
        {menu && (
          <div className="lg:hidden px-4 sm:px-6 pb-4 space-y-1" style={{ borderTop:"1px solid rgba(212,175,55,0.08)" }}>
            {[["home",t.nav[0]],["specialties",t.nav[1]],["destinations",t.nav[2]],["booking",t.book],["patient",t.nav[3]],["shop","Boutique"]].map(([s,l]) => (
              <button key={s} onClick={() => go(s)} className="block w-full text-left px-4 py-3 rounded-xl text-sm font-medium transition-colors hover:bg-white/5" style={{ color:"rgba(255,255,255,0.7)" }}>{l}</button>
            ))}
          </div>
        )}
      </header>

      <main>
        {section==="home" && (
          <>
            <Hero t={t} go={go}/>
            <Specialties t={t} lang={lang} setModal={setModal}/>
            <EhpadSection t={t} go={go}/>
            <Destinations t={t} lang={lang} setDestModal={setDestModal}/>
          </>
        )}
        {section==="specialties" && <Specialties t={t} lang={lang} setModal={setModal}/>}
        {section==="destinations" && <Destinations t={t} lang={lang} setDestModal={setDestModal}/>}
        {section==="booking" && <Booking sp={bookSp} lang={lang} t={t} onBack={() => go("patient")} onConfirmed={handleAppointmentConfirmed}/>}
        {section==="patient" && (
          <PatientPortal
            t={t}
            lang={lang}
            cart={cart}
            goShop={() => go("shop")}
            goBooking={() => go("booking")}
            pendingAppointment={pendingAppointment}
            clearPendingAppointment={() => setPendingAppointment(null)}
          />
        )}
        {section==="shop" && <Shop lang={lang} cart={cart} setCart={setCart} onBack={() => go("patient")} onCheckout={() => go("checkout")}/>}
        {section==="checkout" && <Checkout lang={lang} cart={cart} setCart={setCart} onBack={() => go("shop")} onSuccess={() => go("patient")}/>}
      </main>

      <Footer t={t}/>
      <AiChat lang={lang}/>

      {modal && <SpecModal sp={modal} lang={lang} t={t} onClose={() => setModal(null)} onBook={sp => { setBookSp(sp); setModal(null); go("booking"); }}/>}
      {destModal && <DestModal d={destModal} lang={lang} t={t} onClose={() => setDestModal(null)}/>}
    </div>
  );
}

